final:
module top_module(I, O, S0, S1);input [3:0] I;
  output O;
  input S0, S1;

  reg [3:0] selected_input;
  always @ (S0, S1, I) begin
    case ({S1, S0})
      2'b00: selected_input = I[0];
      2'b01: selected_input = I[1];
      2'b10: selected_input = I[2];
      2'b11: selected_input = I[3];
    endcase
  end

  assign O = selected_input;
endmodule
